using Frame.DataAccess;
using Frame.BusinessLogic.Interfaces; using Frame.Domain.Entities; using Microsoft.Extensions.Configuration; using Microsoft.IdentityModel.Tokens; using System.IdentityModel.Tokens.Jwt; using System.Security.Claims; using System.Text;  namespace Frame.BusinessLogic.Services {     public class TokenService : ITokenService     {         private readonly SymmetricSecurityKey _key;          public TokenService(IConfiguration config)         {             var tokenKey = config["Jwt:Key"];             if (string.IsNullOrEmpty(tokenKey))             {                 throw new ArgumentNullException("Jwt:Key is not configured in appsettings.json");             }             _key = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(tokenKey));         }          public string CreateToken(User user)         {             var claims = new List<Claim>             {                 new Claim(JwtRegisteredClaimNames.NameId, user.Username),                 new Claim(ClaimTypes.Role, user.Role)             };              var creds = new SigningCredentials(_key, SecurityAlgorithms.HmacSha512Signature);              var tokenDescriptor = new SecurityTokenDescriptor             {                 Subject = new ClaimsIdentity(claims),                 Expires = DateTime.Now.AddDays(7),                 SigningCredentials = creds             };              var tokenHandler = new JwtSecurityTokenHandler();             var token = tokenHandler.CreateToken(tokenDescriptor);              return tokenHandler.WriteToken(token);         }     } }
